'use strict';
// ─────────────────────────────────────────────────────────────────────────────
// docGenerator.js — Módulo de generación del Resumen Ejecutivo
// Extraído del generador original de Montpalm Capital Partners
// Importa este módulo con: const { generateResumenEjecutivo } = require('./docGenerator');
// ─────────────────────────────────────────────────────────────────────────────

const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, Header, Footer, AlignmentType, BorderStyle, WidthType,
  ShadingType, SimpleField, TabStopType, VerticalAlign, PageOrientation
} = require('docx');
const fs = require('fs');

// ── Brand ──────────────────────────────────────────────
const VINO      = "4E0E1A";
const VINO_LITE = "F5EEEF";
const GRAY_LINE = "CCCCCC";
const GRAY_TXT  = "666666";
const GRAY_DARK = "333333";
const BLACK     = "1A1A1A";
const WHITE     = "FFFFFF";

const LOGO_CLEAN_B64 = "";
const LOGO_FADED_B64 = "";

const logoBuffer    = Buffer.from(LOGO_CLEAN_B64, 'base64');
const logoFaded     = Buffer.from(LOGO_FADED_B64, 'base64');
const logoB64Clean  = LOGO_CLEAN_B64;

// ── Page constants (A4 landscape) ───────────────────────
const MARGIN  = 500;
const CONTENT = 16838 - MARGIN * 2;

// ── Doc helpers ─────────────────────────────────────────
const noBorder  = { style: BorderStyle.NONE, size: 0, color: WHITE };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };
function cb(c = GRAY_LINE) { return { style: BorderStyle.SINGLE, size: 1, color: c }; }
function borders(c = GRAY_LINE) { const b = cb(c); return { top: b, bottom: b, left: b, right: b }; }
function space(pt = 120) { return new Paragraph({ spacing: { before: 0, after: pt }, children: [] }); }

function logoImg(wCm, hCm, faded = false) {
  return new ImageRun({ data: faded ? logoFaded : logoBuffer, transformation: { width: Math.round(wCm*37.795), height: Math.round(hCm*37.795) }, type: 'png' });
}

function sectionHeader(text, width) {
  return new Table({
    width: { size: width, type: WidthType.DXA }, columnWidths: [width], borders: noBorders,
    rows: [new TableRow({ children: [
      new TableCell({
        borders: { top: noBorder, bottom: noBorder, left: { style: BorderStyle.SINGLE, size: 14, color: VINO }, right: noBorder },
        shading: { fill: VINO_LITE, type: ShadingType.CLEAR },
        width: { size: width, type: WidthType.DXA },
        margins: { top: 80, bottom: 80, left: 180, right: 180 },
        children: [new Paragraph({ children: [new TextRun({ text: text.toUpperCase(), font: "Georgia", size: 20, bold: true, color: VINO })] })]
      })
    ]})]
  });
}

function ecoRow(label, value, shaded = false, highlight = false) {
  const fill = highlight ? VINO_LITE : (shaded ? "F7F7F7" : WHITE);
  const mg = { top: 80, bottom: 80, left: 160, right: 160 };
  const col1 = Math.round(LEFT_W * 0.62);
  const col2 = LEFT_W - col1;
  return new TableRow({ children: [
    new TableCell({ borders: borders(), shading: { fill, type: ShadingType.CLEAR }, width: { size: col1, type: WidthType.DXA }, margins: mg,
      children: [new Paragraph({ children: [new TextRun({ text: label, font: "Georgia", size: 20, bold: true, color: highlight ? VINO : GRAY_DARK })] })] }),
    new TableCell({ borders: borders(), shading: { fill, type: ShadingType.CLEAR }, width: { size: col2, type: WidthType.DXA }, margins: mg,
      children: [new Paragraph({ alignment: AlignmentType.RIGHT, children: [new TextRun({ text: value || " ", font: "Georgia", size: 20, bold: highlight, color: highlight ? VINO : BLACK })] })] }),
  ]});
}

function photoBox(width, height, label) {
  return new Table({
    width: { size: width, type: WidthType.DXA }, columnWidths: [width], borders: noBorders,
    rows: [new TableRow({ children: [
      new TableCell({
        borders: borders(GRAY_LINE), shading: { fill: "EEEEEE", type: ShadingType.CLEAR },
        width: { size: width, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 0, right: 0 },
        verticalAlign: VerticalAlign.CENTER,
        children: [
          new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: Math.round((height - 60) / 2), after: 0 },
            children: [new TextRun({ text: label, font: "Georgia", size: 20, color: "BBBBBB", bold: true })] }),
          new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 40, after: Math.round((height - 60) / 2) },
            children: [new TextRun({ text: "(insertar imagen)", font: "Georgia", size: 17, color: "BBBBBB", italics: true })] }),
        ]
      })
    ]})]
  });
}

function makeFooter() {
  return new Footer({ children: [
    new Paragraph({
      border: { top: { style: BorderStyle.SINGLE, size: 2, color: GRAY_LINE, space: 1 } },
      spacing: { before: 80, after: 0 },
      tabStops: [{ type: TabStopType.RIGHT, position: CONTENT }],
      children: [
        new TextRun({ text: "Montpalm Capital Partners, S.L.  —  www.montpalm.com", font: "Georgia", size: 15, color: GRAY_TXT }),
        new TextRun({ text: "\t", font: "Georgia", size: 15 }),
        new TextRun({ text: "Confidencial — Esta información es meramente orientativa y no reviste carácter contractual", font: "Georgia", size: 15, color: GRAY_TXT, italics: true }),
      ]
    })
  ]});
}

const LEFT_W  = Math.round(CONTENT * 0.42);
const GAP     = 280;
const RIGHT_W = CONTENT - LEFT_W - GAP;

// ── GENERATE DOCX ───────────────────────────────────────
function generateResumenEjecutivo(data) {
  const {
    tipo_activo = "[TIPO DE ACTIVO]",
    ciudad = "Madrid",
    mercado = "Prime",
    calle = "",
    numero_via = "",
    codigo_postal = "",
    descripcion = "",
    superficie = "",
    ref_catastral = "",
    num_unidades = "",
    num_unidades_residenciales = "",
    num_habitaciones = "",
    superficie_util = "",
    altura_libre = "",
    num_locales_comerciales = "",
    planta = "",
    num_plantas_totales = "",
    num_plantas_local = "",
    anio_construccion = "",
    uso_urbanistico = "",
    tipo_uso = "",
    edificabilidad = "",
    ocupacion = "",
    uso = "",
    estado = "",
    renta_anual = "",
    renta_mensual = "",
    revpar = "",
    rentabilidad_bruta = "",
    rentabilidad_neta = "",
    precio_m2 = "",
    precio_habitacion = "",
    precio_m2_suelo = "",
    precio_m2t = "",
    precio_venta = "",
    foto1 = "",
    foto2 = "",
    foto3 = "",
    mapa = "",
  } = data;

  // Formateo numérico español sin depender de ICU (funciona en Node slim)
  // 1234567   → "1.234.567"
  // 1234.56   → "1.234,56"
  function fmtInt(n) {
    if (n === "" || n === null || n === undefined) return "";
    return String(Math.round(Number(n))).replace(/\B(?=(\d{3})+(?!\d))/g, ".");
  }
  function fmtDec(n, dec = 2) {
    if (n === "" || n === null || n === undefined) return "";
    const fixed = Number(n).toFixed(dec);          // "1234.56"
    const [int, frac] = fixed.split(".");
    const intFmt = int.replace(/\B(?=(\d{3})+(?!\d))/g, ".");
    return intFmt + "," + frac;
  }

  // Dirección con código postal
  const direccion = calle
    ? (calle
        + (numero_via   ? ", " + numero_via   : "")
        + (codigo_postal ? ", " + codigo_postal : ""))
    : "[DIRECCIÓN COMPLETA]";

  // Helper: create image cell if photo provided, else placeholder
  function photoCell(w, b64, label) {
    if (b64 && b64.length > 100) {
      const imgBuf = Buffer.from(b64.split(',')[1] || b64, 'base64');
      const ext = b64.startsWith('data:image/png') ? 'png' : 'jpg';
      // w is in DXA. 1 inch = 1440 DXA. 1 inch = 96px at screen but Word uses EMU.
      // ImageRun transformation uses pixels at 96dpi. 1440 DXA = 1 inch = 96px
      // w is DXA. 1440 DXA = 1 inch. Word screen resolution = 96dpi.
      // Fit image exactly to cell width, 4:3 height
      const wPx = Math.round(w * 96 / 1440);
      const hPx = Math.round(wPx * 0.62); // Constrained height to keep everything on 1 page
      return new TableCell({
        borders: borders(GRAY_LINE),
        width: { size: w, type: WidthType.DXA },
        margins: { top: 0, bottom: 0, left: 0, right: 0 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({
          alignment: AlignmentType.CENTER, spacing: { before: 0, after: 0 },
          children: [new ImageRun({ data: imgBuf,
            transformation: { width: wPx, height: hPx },
            type: ext
          })]
        })]
      });
    }
    return new TableCell({
      borders: borders(GRAY_LINE), shading: { fill: "EEEEEE", type: ShadingType.CLEAR },
      width: { size: w, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 0, right: 0 },
      verticalAlign: VerticalAlign.CENTER,
      children: [
        new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 500, after: 0 },
          children: [new TextRun({ text: label, font: "Georgia", size: 18, color: "BBBBBB", bold: true })] }),
        new Paragraph({ alignment: AlignmentType.CENTER, spacing: { before: 40, after: 500 },
          children: [new TextRun({ text: "(insertar imagen)", font: "Georgia", size: 15, color: "BBBBBB", italics: true })] }),
      ]
    });
  }

  // Map cell
  function mapCell(w, h, b64) {
    if (b64 && b64.length > 100) {
      const imgBuf = Buffer.from(b64.split(',')[1] || b64, 'base64');
      // Map canvas is square — use width as both dimensions
      return new Table({
        width: { size: w, type: WidthType.DXA }, columnWidths: [w], borders: noBorders,
        rows: [new TableRow({ children: [
          new TableCell({
            borders: borders(GRAY_LINE), width: { size: w, type: WidthType.DXA },
            margins: { top: 0, bottom: 0, left: 0, right: 0 },
            children: [new Paragraph({
              alignment: AlignmentType.CENTER, spacing: { before: 0, after: 0 },
              children: [new ImageRun({ data: imgBuf,
                // w=RIGHT_W=8906 DXA=594px, h=6014 DXA=401px
                transformation: { width: Math.round(w * 96 / 1440), height: Math.round(h * 96 / 1440) },
                type: 'png'
              })]
            })]
          })
        ]})]
      });
    }
    return photoBox(w, h, "📍 MAPA / UBICACIÓN");
  }

  const doc = new Document({
    styles: { default: { document: { run: { font: "Georgia", size: 19 } } } },
    sections: [{
      properties: {
        page: {
          size: { width: 11906, height: 16838, orientation: PageOrientation.LANDSCAPE },
          margin: { top: 500, right: MARGIN, bottom: 500, left: MARGIN }
        }
      },
      footers: { default: makeFooter() },
      children: [

        // ── HEADER: Logo | Asset info ─────────────────
        new Table({
          width: { size: CONTENT, type: WidthType.DXA },
          columnWidths: [LEFT_W + GAP, CONTENT - LEFT_W - GAP],
          borders: noBorders,
          rows: [new TableRow({ children: [
            new TableCell({
              borders: noBorders, width: { size: LEFT_W + GAP, type: WidthType.DXA },
              margins: { top: 0, bottom: 80, left: 0, right: 0 }, verticalAlign: VerticalAlign.CENTER,
              children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [logoImg(6.0, 3.02)] })]
            }),
            new TableCell({
              borders: { top: noBorder, bottom: noBorder, left: { style: BorderStyle.SINGLE, size: 6, color: VINO }, right: noBorder },
              width: { size: CONTENT - LEFT_W - GAP, type: WidthType.DXA },
              margins: { top: 60, bottom: 60, left: 220, right: 0 }, verticalAlign: VerticalAlign.CENTER,
              children: [
                new Paragraph({ children: [
                  new TextRun({ text: tipo_activo, font: "Georgia", size: 26, bold: true, color: VINO }),
                  new TextRun({ text: `  |  ${ciudad}  |  ${mercado}`, font: "Georgia", size: 22, color: GRAY_TXT }),
                ]}),
                new Paragraph({ spacing: { before: 60, after: 0 }, children: [
                  new TextRun({ text: direccion, font: "Georgia", size: 28, bold: true, color: BLACK }),
                ]}),
              ]
            }),
          ]})]
        }),

        // Divider: full left cell (no border) + right cell with vino bottom border
        new Table({
          width: { size: CONTENT, type: WidthType.DXA },
          columnWidths: [LEFT_W + GAP, CONTENT - LEFT_W - GAP],
          borders: noBorders,
          rows: [new TableRow({ children: [
            new TableCell({
              borders: { top: noBorder, bottom: { style: BorderStyle.SINGLE, size: 6, color: VINO }, left: noBorder, right: noBorder },
              width: { size: LEFT_W + GAP, type: WidthType.DXA },
              margins: { top: 80, bottom: 80, left: 0, right: 0 },
              children: [space(0)]
            }),
            new TableCell({
              borders: { top: noBorder, bottom: { style: BorderStyle.SINGLE, size: 6, color: VINO }, left: noBorder, right: noBorder },
              width: { size: CONTENT - LEFT_W - GAP, type: WidthType.DXA },
              margins: { top: 80, bottom: 80, left: 0, right: 0 },
              children: [space(0)]
            }),
          ]})]
        }),
        space(100),

        // ── MAIN 2-COL LAYOUT ─────────────────────────
        new Table({
          width: { size: CONTENT, type: WidthType.DXA },
          columnWidths: [LEFT_W, GAP, RIGHT_W],
          borders: noBorders,
          rows: [new TableRow({ children: [

            // LEFT: Resumen + Condiciones
            new TableCell({
              borders: noBorders, width: { size: LEFT_W, type: WidthType.DXA },
              margins: { top: 0, bottom: 0, left: 0, right: 0 }, verticalAlign: VerticalAlign.TOP,
              children: [
                sectionHeader("Resumen Ejecutivo", LEFT_W),
                space(80),
                new Paragraph({ alignment: AlignmentType.JUSTIFIED, spacing: { before: 0, after: 120 },
                  children: [new TextRun({ text: descripcion, font: "Georgia", size: 24, color: BLACK })] }),
                space(80),
                // Bullet points dinámicos según tipo de activo
                ...((() => {
                  const t = (tipo_activo || "").toUpperCase();
                  const sup = superficie ? `Superficie construida: ${fmtInt(superficie)} m²` : null;
                  const ref = ref_catastral ? `Referencia catastral: ${ref_catastral}` : null;
                  const est = estado ? `Estado del activo: ${estado}` : null;
                  const ocu = ocupacion ? `Ocupación: ${fmtDec(ocupacion, 1)}%` : null;

                  let extra = [];
                  if (t === "EDIFICIO RESIDENCIAL") {
                    if (num_unidades) extra.push(`Nº de unidades: ${fmtInt(num_unidades)}`);
                  } else if (t === "EDIFICIO MIXTO") {
                    if (num_unidades_residenciales) extra.push(`Unidades residenciales: ${fmtInt(num_unidades_residenciales)}`);
                    if (num_locales_comerciales) extra.push(`Locales comerciales: ${fmtInt(num_locales_comerciales)}`);
                  } else if (t === "PISOS") {
                    if (num_habitaciones) extra.push(`Nº de habitaciones: ${fmtInt(num_habitaciones)}`);
                    if (planta) extra.push(`Planta: ${planta}`);
                  } else if (t === "OFICINAS") {
                    if (superficie_util) extra.push(`Superficie útil: ${fmtInt(superficie_util)} m²`);
                    if (num_plantas_totales) extra.push(`Nº de plantas: ${fmtInt(num_plantas_totales)}`);
                  } else if (t === "LOCAL COMERCIAL") {
                    if (altura_libre) extra.push(`Altura libre: ${fmtDec(altura_libre, 2)} m`);
                    if (num_plantas_local) extra.push(`Nº de plantas: ${fmtInt(num_plantas_local)}`);
                  } else if (t === "HOTEL") {
                    if (num_habitaciones) extra.push(`Nº de habitaciones: ${fmtInt(num_habitaciones)}`);
                    if (anio_construccion) extra.push(`Año de construcción: ${anio_construccion}`);
                  } else if (t === "SUELO") {
                    if (edificabilidad) extra.push(`Edificabilidad: ${fmtInt(edificabilidad)} m²`);
                    if (uso_urbanistico) extra.push(`Uso urbanístico: ${uso_urbanistico}`);
                  } else if (t === "OTRO") {
                    if (num_unidades) extra.push(`Nº de unidades: ${fmtInt(num_unidades)}`);
                    if (tipo_uso) extra.push(`Tipo de uso: ${tipo_uso}`);
                  }

                  return [sup, ref, ...extra, ocu, est].filter(Boolean);
                })()).map(item =>
                  new Paragraph({
                    spacing: { before: 40, after: 60 },
                    indent: { left: 400, hanging: 300 },
                    children: [
                      new TextRun({ text: "■  ", font: "Arial", size: 16, color: VINO }),
                      new TextRun({ text: item, font: "Georgia", size: 24, color: BLACK }),
                    ]
                  })
                ),
                space(160),
                sectionHeader("Condiciones Económicas", LEFT_W),
                space(80),
                new Table({
                  width: { size: LEFT_W, type: WidthType.DXA }, columnWidths: [LEFT_W], borders: noBorders,
                  rows: (() => {
                    const t = (tipo_activo || "").toUpperCase();
                    const rows = [];
                    // Renta: label y valor según tipo
                    if (t === "HOTEL") {
                      rows.push(ecoRow("RevPAR:", revpar ? `${fmtInt(revpar)} €` : "—", false));
                    } else if (t === "PISOS" || t === "LOCAL COMERCIAL" || t === "OFICINAS") {
                      rows.push(ecoRow("Renta mensual:", renta_mensual ? `${fmtInt(renta_mensual)} €` : "—", false));
                    } else {
                      rows.push(ecoRow("Renta anual bruta:", renta_anual ? `${fmtInt(renta_anual)} €` : "—", false));
                    }
                    // Rentabilidades (no para Suelo ni Hotel)
                    if (t !== "SUELO") {
                      rows.push(ecoRow("Rentabilidad bruta:", rentabilidad_bruta ? `${fmtDec(rentabilidad_bruta, 2)}%` : "—", true));
                      rows.push(ecoRow("Rentabilidad neta:", rentabilidad_neta ? `${fmtDec(rentabilidad_neta, 2)}%` : "—", false));
                    }
                    // Precio por m² / habitación / suelo
                    if (t === "HOTEL") {
                      rows.push(ecoRow("Precio por habitación:", precio_habitacion ? `${fmtInt(precio_habitacion)} €` : "—", true));
                    } else if (t === "SUELO") {
                      rows.push(ecoRow("Precio por m² suelo:", precio_m2_suelo ? `${fmtInt(precio_m2_suelo)} €/m²` : "—", true));
                      rows.push(ecoRow("Precio por m²t:", precio_m2t ? `${fmtInt(precio_m2t)} €/m²t` : "—", false));
                    } else {
                      rows.push(ecoRow("Precio por m²:", precio_m2 ? `${fmtInt(precio_m2)} €/m²` : "—", true));
                    }
                    rows.push(ecoRow("Precio estimado de venta:", precio_venta ? `${fmtInt(precio_venta)} €` : "—", t === "SUELO" ? true : false, true));
                    return rows;
                  })()
                }),
              ]
            }),

            // GAP
            new TableCell({ borders: noBorders, width: { size: GAP, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 0, right: 0 }, children: [space(0)] }),

            // RIGHT: Gallery + Map
            new TableCell({
              borders: noBorders, width: { size: RIGHT_W, type: WidthType.DXA },
              margins: { top: 0, bottom: 0, left: 0, right: 0 }, verticalAlign: VerticalAlign.TOP,
              children: [
                sectionHeader("Galería Fotográfica", RIGHT_W),
                space(80),
                (() => {
                  const G = 80, oneW = Math.round((RIGHT_W - G * 2) / 3), lastW = RIGHT_W - oneW * 2 - G * 2;
                  function gapCell() {
                    return new TableCell({ borders: noBorders, width: { size: G, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 0, right: 0 }, children: [space(0)] });
                  }
                  return new Table({
                    width: { size: RIGHT_W, type: WidthType.DXA }, columnWidths: [oneW, G, oneW, G, lastW], borders: noBorders,
                    rows: [new TableRow({ children: [
                      photoCell(oneW, foto1, "[FOTO 1]"),
                      gapCell(),
                      photoCell(oneW, foto2, "[FOTO 2]"),
                      gapCell(),
                      photoCell(lastW, foto3, "[FOTO 3]"),
                    ]})]
                  });
                })(),
                space(160),
                sectionHeader("Ubicación", RIGHT_W),
                space(80),
                mapCell(RIGHT_W, 3800, mapa),  // 4235 DXA = 7.47cm — aligns with honorarios
              ]
            }),
          ]})]
        }),
      ]
    }]
  });

  return Packer.toBuffer(doc);
}

module.exports = { generateResumenEjecutivo };
